 1	import React, { FC } from 'react';
 2	
 3	import { Button, ButtonVariant, Checkbox, Flex, FlexItem, Popover } from '@patternfly/react-core';
 4	import { HelpIcon } from '@patternfly/react-icons';
 5	
 6	import ExternalLink from '../ExternalLink/ExternalLink';
 7	
 8	import './EnableFeatureCheckbox.scss';
 9	
10	type EnableFeatureCheckboxControlledProps = {
11	  canEdit: boolean;
12	  description?: string;
13	  externalLink?: string;
14	  featureEnabled: boolean;
15	  helpText?: string;
16	  id: string;
17	  isDisabled?: boolean;
18	  label: string;
19	  loading: boolean;
20	  toggleFeature: (val: boolean) => void;
21	};
22	
23	const EnableFeatureCheckboxControlled: FC<EnableFeatureCheckboxControlledProps> = ({
24	  canEdit,
25	  description,
26	  externalLink,
27	  featureEnabled,
28	  helpText,
29	  id,
30	  label,
31	  loading,
32	  toggleFeature,
33	}) => {
34	  return (
35	    <Flex>
36	      <FlexItem className="enable-feature-checkbox">
37	        <Flex spaceItems={{ default: 'spaceItemsNone' }}>
38	          <Checkbox
39	            onClick={(event) => {
40	              toggleFeature(event?.currentTarget?.checked);
41	            }}
42	            checked={featureEnabled}
43	            description={description}
44	            id={id}
45	            isDisabled={!canEdit || loading}
46	            label={label}
47	          />
48	          {helpText && (
49	            <Popover bodyContent={helpText}>
50	              <Button variant={ButtonVariant.plain}>
51	                <HelpIcon />
52	              </Button>
53	            </Popover>
54	          )}
55	        </Flex>
56	      </FlexItem>
57	      {externalLink && (
58	        <FlexItem>
59	          <ExternalLink href={externalLink} />
60	        </FlexItem>
61	      )}
62	    </Flex>
63	  );
64	};
65	
66	export default EnableFeatureCheckboxControlled;

